class ReCaptcha{constructor(a,b,c,d){this.canvas=document.getElementById(a),this.input=document.getElementById(b),this.button=document.getElementById(c),this.ctx=this.canvas.getContext("2d"),this.siteKey=d,this.code="",this.generate(),this.button.addEventListener("click",()=>this.verify())}generate(){let a="ABCDEFGHJKLMNPQRSTUVWXYZ23456789";this.code="";for(let b=0;b<6;b++)this.code+=a[Math.floor(Math.random()*a.length)];this.draw()}draw(){this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height),this.ctx.fillStyle="#f2f2f2",this.ctx.fillRect(0,0,this.canvas.width,this.canvas.height),this.ctx.font="30px Arial",this.ctx.fillStyle="#222";for(let a=0;a<this.code.length;a++){let b=20+25*a,c=40+10*Math.random();this.ctx.save(),this.ctx.translate(b,c),this.ctx.rotate(.4*(Math.random()-.5)),this.ctx.fillText(this.code[a],0,0),this.ctx.restore()}}verify(){this.input.value.toUpperCase()===this.code?alert("CAPTCHA PASSED ✔\nSite Key: "+this.siteKey):(alert("FAILED ❌"),this.generate())}}
